1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_PERCENT = 110;
3	
4	type Item = { type: string };
5	type Scenario = { steps: { items: Item[] }[] };
6	
7	const BASE_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	  rune: 25,
13	};
14	
15	const policyBaseFor = (items: Item[]): number => {
16	  const sum = items.reduce((acc, item) => acc + BASE_PREMIUMS[item.type], 0);
17	  const runeCount = items.filter((item) => item.type === "rune").length;
18	  if (runeCount === 3) return sum - 15;
19	  return sum;
20	};
21	
22	export const runScenario = (input: unknown): unknown => {
23	  const items = (input as Scenario).steps[0].items;
24	  const policyBase = policyBaseFor(items);
25	  const premium = Math.ceil((policyBase * FIRST_INSURANCE_PERCENT) / 100) + PROCESSING_FEE;
26	  return { results: [{ premium }] };
27	};
28

